# Source: https://leetcode.com/problems/minimum-size-subarray-in-infinite-array/   |   Difficulty: Medium
#
# Problem Description:
# You are given a 0-indexed array nums and an integer target.
#
# A 0-indexed array infinite_nums is generated by infinitely appending the elements of nums to itself.
#
# Return the length of the shortest subarray of the array infinite_nums with a sum equal to target. If there is no such subarray return -1.
#
# Example:
# Input: nums = [1,2,3], target = 5
# Output: 2
# Explanation: In this example infinite_nums = [1,2,3,1,2,3,1,2,...].
# The subarray in the range [1,2], has the sum equal to target = 5 and length = 2.
# It can be proven that 2 is the shortest length of a subarray with sum equal to target = 5.
#
# Constraints:
# 1 <= nums.length <= 105
# 	1 <= nums[i] <= 105
# 	1 <= target <= 109
#

class Solution(object):
    def minSizeSubarray(self, nums, target):
        """
        :type nums: List[int]
        :type target: int
        :rtype: int
        """
        n = len(nums)
        total = sum(nums)
        min_length = float('inf')

        # Check subarrays within a single repetition of nums
        left = 0
        current_sum = 0
        for right in range(n):
            current_sum += nums[right]
            while current_sum > target and left <= right:
                current_sum -= nums[left]
                left += 1
            if current_sum == target:
                min_length = min(min_length, right - left + 1)

        # Check subarrays that span multiple repetitions of nums
        if total < target:
            full_repeats = target // total
            remainder = target % total
            if remainder == 0:
                min_length = min(min_length, full_repeats * n)
            else:
                left = 0
                current_sum = 0
                for right in range(n):
                    current_sum += nums[right]
                    while current_sum > remainder and left <= right:
                        current_sum -= nums[left]
                        left += 1
                    if current_sum == remainder:
                        min_length = min(min_length, full_repeats * n + (right - left + 1))

        return min_length if min_length != float('inf') else -1